  GetGender() {
    this.http
      .get<IGender[]>(this.env.API_URL + "api/StaticRef/GetGender")
      .subscribe((data) => {
        this.Genders = data;
      });
  }
  async GetMartialStatus() {
    return this.http
      .get<IMartialStatus[]>(
        this.env.API_URL + "api/StaticRef/GetMaritalStatus"
      )
      .subscribe((data) => {
        this.MartialStatusObjects = data;
      });
  }

  async getAllBranches() {
    let params = new HttpParams();
    params = params.set("org_code", this.org_code_user_info);
    params = params.set(
      "gov_code",
      this.BusinessDataForm.controls.GovCode.value
    );

    if (this.ClientLat && this.ClientLat != null) {
      params = params.set("client_Lat", this.ClientLat);
      params = params.set("client_Long", this.ClientLong);
    }

    return this.http
      .get<IBranch[]>(
        this.env.API_URL +
          `api/ClientRegistration/GetAllBranches?${params.toString()}`,
        {}
      )
      .subscribe({
        next: (data) => {
          this.getAllBranchesObjects = data;
          if (this.ClientLat != null && this.ClientLong != null) {
            this.selectBranch = this.getAllBranchesObjects[0].branch_code;
          }
        },
        error: (err) => {},
      });
  }

