  async takePicture(index: number): Promise<void> {
    let cameraResult = await this.cameraService.getPhoto();
    if (cameraResult.success) {
      this.photo = cameraResult.photo;
      this.picture[index] = this.photo;
      this.imageSrc = "data:image/jpg;base64," + this.photo.base64String;

      this.imageModal.present();
      this.uploadPicture(index);
    } else {
      await this.alertSerivce.showAlertError(cameraResult.message, false);
    }
  }

  uploadPicture(index: number): void {
    let orgCode = this.UnconfirmedDocumentObjects.orgCode;
    let documentSerial = this.UnconfirmedDocumentObjects.documentSerial;
    let documentTypeCode = this.UnconfirmedDocumentObjects.documentTypeCode;

    this.http
      .post(
        this.env.API_URL + `api/ClientRegistration/UploadUnconfirmedImage`,
        {
          orgCode,
          documentSerial,
          documentTypeCode,
          // ...this.currentDocument,
          pageNumber: index + 1,
          image: this.photo.base64String,
        }
      )
      .subscribe({
        next: (data) => {
          //this.showLoader = false;
          this.presentToast("تم", "تم رفع الصورة بنجاح");
        },
        error: (err) => {
          //this.showLoader = false;
          this.documentDetails[index] = null;
          this.presentToast("خطأ", "خطأ في رفع الصورة");
        },
      });
  }

  getDistinctValues(data: any[], distinct_name: string): any[] {
    const values = data.map((item: any) => item[distinct_name]);
    const distinctValues = values.filter(
      (value: any, index: number, array: any[]) =>
        value != null && array.indexOf(value) === index
    );
    return distinctValues;
  }

  GetClientDocs() {
    // this.ClientDocuments = this.EditClient["result"]["clientDocDetails"];
    this.allDocs = this.getDistinctValues(this.ClientDocuments, "doc_image");
  }

  isImageValid(index: number): boolean {
    let image = this.picture[index];
    return !!image && image != "" && /^[a-zA-Z0-9\+/]*={0,3}$/.test(this.photo);
  }

  showCurrentDocuments() {
    this.displayDocuments = !this.displayDocuments;
  }

  backToClient(): void {
    this.imageSrc = null;
    this.documentDetails = null;
    // this.currentDocument = null;
    this.isDocumentSelected = false;
  }

  backButton(): void {
    // Client selected
    if (this.isDocumentSelected) {
      this.backToClient();
    }
  }
