  // toast and Alert //
  async presentToast(header: string, message: string): Promise<void> {
    let toast = await this.toastCtrl.create({
      header: header,
      message: message,
      cssClass: "toast-primary",
      duration: 2000,
      position: "bottom",
    });
    await toast.present();
  }

  async ErrorToast(message: string) {
    let toast = await this.toastCtrl.create({
      header: "",
      message: (message = message), //or text 'رقم الموبايل مسجل لدينا من قبل – برجاء تسجيل الدخول او اختيار رقم اخر'
      position: "middle",
      duration: 10000,
      color: "dark",
      keyboardClose: true,
      //show buttons in toast
      buttons: [
        {
          side: "start",
        },

        {
          icon: "close", //key to close toast
          role: "cancel", //key order to close toast
          side: "start",
        },
      ],
      cssClass: "ion-text-center",
    });
    await toast.present();
  }

  noWhitespaceValidator(control: FormControl) {
    const isWhitespace =
      control.value !== null &&
      (control.value || "").toString().trim().length === 0;
    const isValid = !isWhitespace;
    return isValid ? null : { whitespace: true };
  }

  noDateGreaterToday(control: FormControl) {
    const isDateGrater = new Date(control.value);
    const currentDate = new Date();
    if (isDateGrater > currentDate) {
      return { DateIsGrater: true };
    }
  }
